module.exports = {
  config: {
cooldowns: 10,
credits: 'CHAND',
premium: false,
permission: 0,
version: '1.0.0',
    name: 'setemoji',
    aliases: ['emoji', 'groupemoji'],
    description: 'Change the group emoji',
    usage: 'setemoji [emoji]',
    category: 'Group',
    groupOnly: true,
    prefix: true
  },
  
  async run({ api, event, args, send, config }) {
    const { threadID, senderID } = event;
    
    const threadInfo = await api.getThreadInfo(threadID);
    const adminIDs = threadInfo.adminIDs.map(a => a.id);
    
    const isGroupAdmin = adminIDs.includes(senderID);
    
    const emoji = args[0];
    
    if (!emoji) {
      return send.reply('━❮❌❯━━━❪⚠️❫━━━❮❌❯━\n🔒 🅟𝐥𝐞𝐚𝐬𝐞 𝐩𝐫𝐨𝐯𝐢𝐝𝐞 𝐚𝐧 𝐞𝐦𝐨𝐣𝐢.\n━❮❌❯━━━❪⚠️❫━━━❮❌❯━');
    }
    
    try {
      await api.changeThreadEmoji(emoji, threadID);
      return send.reply(`━❮✅❯━━━❪🎉❫━━━❮✅❯━\n🔒 🅖𝐫𝐨𝐮𝐩 𝐞𝐦𝐨𝐣𝐢 𝐜𝐡𝐚𝐧𝐠𝐞𝐝 𝐭𝐨: ${emoji}\n━❮✅❯━━━❪🎉❫━━━❮✅❯━`);
    } catch (error) {
      return send.reply('Failed to change group emoji.');
    }
  }
};
